import React from 'react';
import { Layout as CarbonLayout } from '@carbon/react';

const Layout = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonLayout
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonLayout>
    );
};

Layout.defaultProps = {
    className: ''
};

export default Layout;
